package com.taskflow.entity;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.EnumSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Pure unit tests for TaskStatus enum.
 * No Spring context needed — tests enum values and state machine logic.
 */
class TaskStatusTest {

    // ── Contract: enum values ──────────────────────────────────────────

    @Test
    @DisplayName("TaskStatus has exactly 4 values: TODO, IN_PROGRESS, DONE, CLOSED")
    void shouldHaveExactlyFourValues() {
        TaskStatus[] values = TaskStatus.values();
        assertEquals(4, values.length);
        assertNotNull(TaskStatus.valueOf("TODO"));
        assertNotNull(TaskStatus.valueOf("IN_PROGRESS"));
        assertNotNull(TaskStatus.valueOf("DONE"));
        assertNotNull(TaskStatus.valueOf("CLOSED"));
    }

    // ── getAllowedTransitions ───────────────────────────────────────────

    @Nested
    @DisplayName("getAllowedTransitions()")
    class GetAllowedTransitionsTests {

        @Test
        @DisplayName("TODO -> [IN_PROGRESS]")
        void todoAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.TODO.getAllowedTransitions();
            assertEquals(1, allowed.size());
            assertTrue(allowed.contains(TaskStatus.IN_PROGRESS));
        }

        @Test
        @DisplayName("IN_PROGRESS -> [TODO, DONE]")
        void inProgressAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.IN_PROGRESS.getAllowedTransitions();
            assertEquals(2, allowed.size());
            assertTrue(allowed.contains(TaskStatus.TODO));
            assertTrue(allowed.contains(TaskStatus.DONE));
        }

        @Test
        @DisplayName("DONE -> [CLOSED]")
        void doneAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.DONE.getAllowedTransitions();
            assertEquals(1, allowed.size());
            assertTrue(allowed.contains(TaskStatus.CLOSED));
        }

        @Test
        @DisplayName("CLOSED -> [] (empty, terminal state)")
        void closedAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.CLOSED.getAllowedTransitions();
            assertNotNull(allowed);
            assertTrue(allowed.isEmpty());
        }
    }

    // ── canTransitionTo — valid transitions ────────────────────────────

    @Nested
    @DisplayName("canTransitionTo() — valid transitions")
    class ValidTransitionTests {

        @Test
        @DisplayName("TODO -> IN_PROGRESS = true")
        void todoToInProgress() {
            assertTrue(TaskStatus.TODO.canTransitionTo(TaskStatus.IN_PROGRESS));
        }

        @Test
        @DisplayName("IN_PROGRESS -> TODO = true")
        void inProgressToTodo() {
            assertTrue(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.TODO));
        }

        @Test
        @DisplayName("IN_PROGRESS -> DONE = true")
        void inProgressToDone() {
            assertTrue(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.DONE));
        }

        @Test
        @DisplayName("DONE -> CLOSED = true")
        void doneToClosed() {
            assertTrue(TaskStatus.DONE.canTransitionTo(TaskStatus.CLOSED));
        }
    }

    // ── canTransitionTo — invalid transitions ──────────────────────────

    @Nested
    @DisplayName("canTransitionTo() — invalid transitions")
    class InvalidTransitionTests {

        @Test
        @DisplayName("TODO -> DONE = false")
        void todoToDone() {
            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.DONE));
        }

        @Test
        @DisplayName("TODO -> CLOSED = false")
        void todoToClosed() {
            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.CLOSED));
        }

        @Test
        @DisplayName("TODO -> TODO = false (self-transition)")
        void todoToTodo() {
            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.TODO));
        }

        @Test
        @DisplayName("DONE -> TODO = false")
        void doneToTodo() {
            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.TODO));
        }

        @Test
        @DisplayName("DONE -> IN_PROGRESS = false")
        void doneToInProgress() {
            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.IN_PROGRESS));
        }

        @Test
        @DisplayName("DONE -> DONE = false (self-transition)")
        void doneToDone() {
            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.DONE));
        }

        @ParameterizedTest(name = "CLOSED -> {0} = false")
        @EnumSource(TaskStatus.class)
        @DisplayName("CLOSED -> anything = false (terminal state)")
        void closedToAnything(TaskStatus target) {
            assertFalse(TaskStatus.CLOSED.canTransitionTo(target));
        }

        @Test
        @DisplayName("IN_PROGRESS -> CLOSED = false")
        void inProgressToClosed() {
            assertFalse(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.CLOSED));
        }

        @Test
        @DisplayName("IN_PROGRESS -> IN_PROGRESS = false (self-transition)")
        void inProgressToInProgress() {
            assertFalse(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.IN_PROGRESS));
        }
    }

    // ── Edge cases ─────────────────────────────────────────────────────

    @Test
    @DisplayName("canTransitionTo with null target should not throw (return false or throw NPE)")
    void canTransitionToNull() {
        // Depending on implementation, this may throw NPE or return false.
        // We simply verify it does not return true.
        try {
            boolean result = TaskStatus.TODO.canTransitionTo(null);
            assertFalse(result);
        } catch (NullPointerException e) {
            // Also acceptable behavior
        }
    }
}

package com.taskflow.entity;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Integration tests for Task entity JPA mapping and defaults.
 * Uses @DataJpaTest with embedded H2.
 */
@DataJpaTest
class TaskEntityTest {

    @Autowired
    private TestEntityManager entityManager;

    // ── Default values ─────────────────────────────────────────────────

    @Test
    @DisplayName("New Task defaults: status=TODO, deleted=false")
    void newTaskShouldHaveDefaultStatusAndDeletedFlag() {
        Task task = new Task();
        task.setTitle("Test Task");
        task.setCreatedBy(1L);

        assertEquals(TaskStatus.TODO, task.getStatus());
        assertFalse(task.isDeleted());
    }

    // ── JPA persistence ────────────────────────────────────────────────

    @Test
    @DisplayName("Task can be persisted and retrieved with all fields intact")
    void shouldPersistAndRetrieveTask() {
        Task task = new Task();
        task.setTitle("Persisted Task");
        task.setDescription("A description");
        task.setCreatedBy(42L);

        Task saved = entityManager.persistAndFlush(task);
        entityManager.clear();

        Task found = entityManager.find(Task.class, saved.getId());
        assertNotNull(found);
        assertEquals("Persisted Task", found.getTitle());
        assertEquals("A description", found.getDescription());
        assertEquals(42L, found.getCreatedBy());
        assertEquals(TaskStatus.TODO, found.getStatus());
        assertFalse(found.isDeleted());
        assertNotNull(found.getCreatedAt());
    }

    @Test
    @DisplayName("Task id is auto-generated on persist")
    void idShouldBeAutoGenerated() {
        Task task = new Task();
        task.setTitle("Auto ID Task");
        task.setCreatedBy(1L);

        assertNull(task.getId());
        Task saved = entityManager.persistAndFlush(task);
        assertNotNull(saved.getId());
    }

    @Test
    @DisplayName("Task createdAt is populated on persist")
    void createdAtShouldBePopulatedOnPersist() {
        Task task = new Task();
        task.setTitle("Timestamp Task");
        task.setCreatedBy(1L);

        Task saved = entityManager.persistAndFlush(task);
        assertNotNull(saved.getCreatedAt());
    }

    @Test
    @DisplayName("Task updatedAt is populated on update")
    void updatedAtShouldBePopulatedOnUpdate() {
        Task task = new Task();
        task.setTitle("Original Title");
        task.setCreatedBy(1L);
        Task saved = entityManager.persistAndFlush(task);

        saved.setTitle("Updated Title");
        entityManager.persistAndFlush(saved);
        entityManager.clear();

        Task found = entityManager.find(Task.class, saved.getId());
        assertNotNull(found.getUpdatedAt());
    }

    // ── Priority enum ──────────────────────────────────────────────────

    @Test
    @DisplayName("Task.Priority inner enum has exactly HIGH, MEDIUM, LOW")
    void priorityEnumShouldHaveThreeValues() {
        Task.Priority[] values = Task.Priority.values();
        assertEquals(3, values.length);
        assertNotNull(Task.Priority.valueOf("HIGH"));
        assertNotNull(Task.Priority.valueOf("MEDIUM"));
        assertNotNull(Task.Priority.valueOf("LOW"));
    }

    @Test
    @DisplayName("Task can persist with each priority value")
    void shouldPersistWithEachPriority() {
        for (Task.Priority priority : Task.Priority.values()) {
            Task task = new Task();
            task.setTitle("Priority " + priority.name());
            task.setPriority(priority);
            task.setCreatedBy(1L);

            Task saved = entityManager.persistAndFlush(task);
            entityManager.clear();

            Task found = entityManager.find(Task.class, saved.getId());
            assertEquals(priority, found.getPriority());
        }
    }

    // ── Contract: field types ──────────────────────────────────────────

    @Test
    @DisplayName("Contract: Task entity has all required fields with correct types")
    void contractFieldsExist() throws NoSuchMethodException {
        // Verify getter methods exist with expected return types
        assertEquals(Long.class, Task.class.getMethod("getId").getReturnType());
        assertEquals(String.class, Task.class.getMethod("getTitle").getReturnType());
        assertEquals(String.class, Task.class.getMethod("getDescription").getReturnType());
        assertEquals(Task.Priority.class, Task.class.getMethod("getPriority").getReturnType());
        assertEquals(TaskStatus.class, Task.class.getMethod("getStatus").getReturnType());
        assertEquals(Long.class, Task.class.getMethod("getCreatedBy").getReturnType());

        // createdAt and updatedAt should be LocalDateTime
        assertEquals(java.time.LocalDateTime.class, Task.class.getMethod("getCreatedAt").getReturnType());
        assertEquals(java.time.LocalDateTime.class, Task.class.getMethod("getUpdatedAt").getReturnType());

        // deleted should be boolean
        assertEquals(boolean.class, Task.class.getMethod("isDeleted").getReturnType());
    }

    // ── Soft delete field ──────────────────────────────────────────────

    @Test
    @DisplayName("Task deleted flag can be toggled and persisted")
    void softDeleteFlagCanBeToggledAndPersisted() {
        Task task = new Task();
        task.setTitle("Deletable Task");
        task.setCreatedBy(1L);

        Task saved = entityManager.persistAndFlush(task);
        assertFalse(saved.isDeleted());

        saved.setDeleted(true);
        entityManager.persistAndFlush(saved);
        entityManager.clear();

        Task found = entityManager.find(Task.class, saved.getId());
        assertTrue(found.isDeleted());
    }

    // ── Status field persistence ───────────────────────────────────────

    @Test
    @DisplayName("Task status can be changed and persisted")
    void statusCanBeChangedAndPersisted() {
        Task task = new Task();
        task.setTitle("Status Task");
        task.setCreatedBy(1L);

        Task saved = entityManager.persistAndFlush(task);
        assertEquals(TaskStatus.TODO, saved.getStatus());

        saved.setStatus(TaskStatus.IN_PROGRESS);
        entityManager.persistAndFlush(saved);
        entityManager.clear();

        Task found = entityManager.find(Task.class, saved.getId());
        assertEquals(TaskStatus.IN_PROGRESS, found.getStatus());
    }
}

package com.taskflow.repository;

import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Integration tests for TaskRepository custom queries.
 * Uses @DataJpaTest with embedded H2.
 */
@DataJpaTest
class TaskRepositoryTest {

    @Autowired
    private TaskRepository taskRepository;

    @Autowired
    private TestEntityManager entityManager;

    private Task createTask(String title, Task.Priority priority, boolean deleted) {
        Task task = new Task();
        task.setTitle(title);
        task.setPriority(priority);
        task.setCreatedBy(1L);
        task.setDeleted(deleted);
        return entityManager.persistAndFlush(task);
    }

    private Task createTask(String title) {
        return createTask(title, Task.Priority.MEDIUM, false);
    }

    // ── Soft-delete exclusion ──────────────────────────────────────────

    @Nested
    @DisplayName("findByDeletedFalse — soft-delete exclusion")
    class SoftDeleteTests {

        @Test
        @DisplayName("Excludes soft-deleted tasks from results")
        void shouldExcludeSoftDeletedTasks() {
            createTask("Active Task 1");
            createTask("Active Task 2");
            createTask("Deleted Task", Task.Priority.MEDIUM, true);

            entityManager.clear();

            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
            assertEquals(2, result.getTotalElements());
            assertTrue(result.getContent().stream().noneMatch(Task::isDeleted));
        }

        @Test
        @DisplayName("Returns empty page when all tasks are soft-deleted")
        void shouldReturnEmptyWhenAllDeleted() {
            createTask("Deleted 1", Task.Priority.MEDIUM, true);
            createTask("Deleted 2", Task.Priority.HIGH, true);

            entityManager.clear();

            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
            assertEquals(0, result.getTotalElements());
            assertTrue(result.getContent().isEmpty());
        }

        @Test
        @DisplayName("Returns all tasks when none are soft-deleted")
        void shouldReturnAllWhenNoneDeleted() {
            createTask("Task 1");
            createTask("Task 2");
            createTask("Task 3");

            entityManager.clear();

            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
            assertEquals(3, result.getTotalElements());
        }
    }

    // ── Keyword search ─────────────────────────────────────────────────

    @Nested
    @DisplayName("Keyword search — case-insensitive title matching")
    class KeywordSearchTests {

        @BeforeEach
        void setUp() {
            createTask("Build login page");
            createTask("Fix LOGIN bug");
            createTask("Design dashboard");
            createTask("Deleted login task", Task.Priority.MEDIUM, true);
            entityManager.clear();
        }

        @Test
        @DisplayName("Finds tasks with matching keyword (case-insensitive)")
        void shouldFindByCaseInsensitiveKeyword() {
            Pageable pageable = PageRequest.of(0, 20);

            // Search for "login" should match "Build login page" and "Fix LOGIN bug"
            // but NOT "Deleted login task" (soft-deleted)
            Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(
                    "login", pageable);
            assertEquals(2, result.getTotalElements());
        }

        @Test
        @DisplayName("Returns empty when no title matches keyword")
        void shouldReturnEmptyWhenNoMatch() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(
                    "nonexistent", pageable);
            assertEquals(0, result.getTotalElements());
        }

        @Test
        @DisplayName("Keyword search excludes soft-deleted tasks")
        void keywordSearchShouldExcludeSoftDeleted() {
            Pageable pageable = PageRequest.of(0, 20);

            // "Deleted login task" is soft-deleted, so only 2 matches
            Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(
                    "login", pageable);
            result.getContent().forEach(task -> assertFalse(task.isDeleted()));
        }
    }

    // ── Priority filter ────────────────────────────────────────────────

    @Nested
    @DisplayName("Priority filter")
    class PriorityFilterTests {

        @BeforeEach
        void setUp() {
            createTask("High priority task", Task.Priority.HIGH, false);
            createTask("Medium priority task", Task.Priority.MEDIUM, false);
            createTask("Low priority task", Task.Priority.LOW, false);
            createTask("Another high task", Task.Priority.HIGH, false);
            createTask("Deleted high task", Task.Priority.HIGH, true);
            entityManager.clear();
        }

        @Test
        @DisplayName("Filters tasks by HIGH priority")
        void shouldFilterByHighPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.HIGH, pageable);
            assertEquals(2, result.getTotalElements());
            result.getContent().forEach(task ->
                    assertEquals(Task.Priority.HIGH, task.getPriority()));
        }

        @Test
        @DisplayName("Filters tasks by MEDIUM priority")
        void shouldFilterByMediumPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.MEDIUM, pageable);
            assertEquals(1, result.getTotalElements());
        }

        @Test
        @DisplayName("Filters tasks by LOW priority")
        void shouldFilterByLowPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.LOW, pageable);
            assertEquals(1, result.getTotalElements());
        }

        @Test
        @DisplayName("Priority filter excludes soft-deleted tasks")
        void priorityFilterShouldExcludeSoftDeleted() {
            Pageable pageable = PageRequest.of(0, 20);

            // 3 HIGH total, but 1 is soft-deleted
            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.HIGH, pageable);
            assertEquals(2, result.getTotalElements());
            result.getContent().forEach(task -> assertFalse(task.isDeleted()));
        }
    }

    // ── Pagination ─────────────────────────────────────────────────────

    @Nested
    @DisplayName("Pagination")
    class PaginationTests {

        @BeforeEach
        void setUp() {
            for (int i = 1; i <= 15; i++) {
                createTask("Task " + i);
            }
            entityManager.clear();
        }

        @Test
        @DisplayName("Returns correct page size")
        void shouldReturnCorrectPageSize() {
            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 5));
            assertEquals(5, result.getContent().size());
            assertEquals(15, result.getTotalElements());
            assertEquals(3, result.getTotalPages());
        }

        @Test
        @DisplayName("Returns correct second page")
        void shouldReturnCorrectSecondPage() {
            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(1, 5));
            assertEquals(5, result.getContent().size());
            assertEquals(1, result.getNumber());
        }

        @Test
        @DisplayName("Returns partial last page")
        void shouldReturnPartialLastPage() {
            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(2, 5));
            assertEquals(5, result.getContent().size());
        }
    }

    // ── Combined filters ───────────────────────────────────────────────

    @Nested
    @DisplayName("Combined keyword + priority filter")
    class CombinedFilterTests {

        @BeforeEach
        void setUp() {
            createTask("Build login page", Task.Priority.HIGH, false);
            createTask("Fix login bug", Task.Priority.MEDIUM, false);
            createTask("Design dashboard", Task.Priority.HIGH, false);
            entityManager.clear();
        }

        @Test
        @DisplayName("Filters by keyword AND priority together")
        void shouldFilterByKeywordAndPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository
                    .findByDeletedFalseAndTitleContainingIgnoreCaseAndPriority(
                            "login", Task.Priority.HIGH, pageable);
            assertEquals(1, result.getTotalElements());
            assertEquals("Build login page", result.getContent().get(0).getTitle());
        }
    }
}

package com.taskflow.dto;

import com.taskflow.entity.Task;
import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Validation tests for CreateTaskRequest DTO.
 * Uses Jakarta Validation directly — no Spring context needed.
 */
class CreateTaskRequestValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setUp() {
        try (ValidatorFactory factory = Validation.buildDefaultValidatorFactory()) {
            validator = factory.getValidator();
        }
    }

    private CreateTaskRequest validRequest() {
        CreateTaskRequest request = new CreateTaskRequest();
        request.setTitle("Valid Title");
        request.setDescription("A valid description");
        request.setPriority(Task.Priority.MEDIUM);
        return request;
    }

    // ── Title validation ───────────────────────────────────────────────

    @Nested
    @DisplayName("Title validation")
    class TitleValidationTests {

        @Test
        @DisplayName("Valid title (1-200 chars) passes validation")
        void validTitlePasses() {
            CreateTaskRequest request = validRequest();
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertTrue(violations.isEmpty());
        }

        @Test
        @DisplayName("Null title fails validation")
        void nullTitleFails() {
            CreateTaskRequest request = validRequest();
            request.setTitle(null);
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertFalse(violations.isEmpty());
        }

        @Test
        @DisplayName("Empty string title fails validation")
        void emptyTitleFails() {
            CreateTaskRequest request = validRequest();
            request.setTitle("");
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertFalse(violations.isEmpty());
        }

        @Test
        @DisplayName("Blank title (whitespace only) fails validation")
        void blankTitleFails() {
            CreateTaskRequest request = validRequest();
            request.setTitle("   ");
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertFalse(violations.isEmpty());
        }

        @Test
        @DisplayName("Title at boundary (exactly 200 chars) passes validation")
        void titleExactly200CharsPasses() {
            CreateTaskRequest request = validRequest();
            request.setTitle("a".repeat(200));
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertTrue(violations.isEmpty());
        }

        @Test
        @DisplayName("Title exceeding 200 chars fails validation")
        void titleExceeding200CharsFails() {
            CreateTaskRequest request = validRequest();
            request.setTitle("a".repeat(201));
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertFalse(violations.isEmpty());
        }

        @Test
        @DisplayName("Single character title (minimum) passes validation")
        void singleCharTitlePasses() {
            CreateTaskRequest request = validRequest();
            request.setTitle("A");
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertTrue(violations.isEmpty());
        }
    }

    // ── Description validation ─────────────────────────────────────────

    @Nested
    @DisplayName("Description validation")
    class DescriptionValidationTests {

        @Test
        @DisplayName("Null description passes (optional field)")
        void nullDescriptionPasses() {
            CreateTaskRequest request = validRequest();
            request.setDescription(null);
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertTrue(violations.isEmpty());
        }

        @Test
        @DisplayName("Empty description passes (optional field)")
        void emptyDescriptionPasses() {
            CreateTaskRequest request = validRequest();
            request.setDescription("");
            Set<ConstraintViolation<CreateTaskRequest>> violations = validator.validate(request);
            assertTrue(violations.isEmpty());
